script:
frappe.ui.form.on('lagna_taq', {
refresh: function(frm) {
        // 🚀 حقن ملف الـ CSS بشكل محلي تماماً داخل هذه الصفحة فقط
        frappe.require('/assets/taq_it/taqafia_global.css');

        // بقية كود الـ سكريبت والترجمة الخاص بك هنا...
    }
})

frappe.ui.form.on("*", {
    refresh: function(frm) {
        // تأكد من كتابة اسم الموديل الفعلي لديك هنا بدلاً من "taqfia" إذا كان مختلفاً في الـ Doctype
        if (frm.meta && frm.meta.module === "taqfia") {

            // 1. تحقق مما إذا كان ملف الـ CSS قد تم استدعاؤه بالفعل، إذا لم يكن، قم بحقنه فوراً
            if (!$("link[href*='taqafia_global.css']").length) {
                $('head').append('<link rel="stylesheet" href="/assets/taq_it/taqafia_global.css" id="taqafia-theme-link">');
            }

        } else {
            // 2. إذا انتقل المستخدم إلى Doctype خارج موديل الثقافية، قم بإزالة ملف الـ CSS فوراً ليعود النظام لشغله الافتراضي
            $("#taqafia-theme-link").remove();
        }
    }
});

frappe.ui.form.on('taq_data1', {
    validate: function(frm) {
        if (frm.doc.agee && frm.doc.agee < 23) {
            frappe.throw(__('يجب أن لا يكون عمر الواعظ أقل من 23 عام'));
        }
    },
    agee: function(frm) {
        if (frm.doc.agee && frm.doc.agee < 23) {
            frappe.msgprint(__('يجب أن لا يكون عمر الواعظ أقل من 23 عام'));
            frm.set_value('agee', '');  // يمسح العمر المدخل
        }
    }
});

frappe.ui.form.on('lagna_taq', {
    refresh: function(frm) {

        // إزالة أي أزرار قديمة بنفس الاسم
        frm.clear_custom_buttons();

        // إضافة زر "عرض التفاصيل" فقط إذا كان هناك مرجع
        if(frm.doc.taq_data1_ref) {
            frm.add_custom_button(__('عرض التفاصيل'), function() {
                frappe.set_route("Form", "taq_data1", frm.doc.taq_data1_ref);
            });
        }
    }
});

frappe.ui.form.on('lagna_taq', {
    refresh: function(frm) {
        if (!frm.doc.moq) {
            frm.set_value('moq', frappe.session.user);
        }
    }
});

frappe.ui.form.on('taq_data1', {
    refresh: function(frm) {
        // 🌫️ خلفية زجاجية ناعمة
        $('body').css({
            'background': 'linear-gradient(135deg, #e3f2fd 0%, #ffffff 100%)',
            'font-family': '"Poppins", "Segoe UI", sans-serif',
            'color': '#1e293b',
            'transition': 'background 0.6s ease'
        });

        // 🧊 الحاوية الرئيسية للفورم
        $('.form-layout').css({
            'background': 'rgba(255, 255, 255, 0.7)',
            'backdrop-filter': 'blur(14px)',
            '-webkit-backdrop-filter': 'blur(14px)',
            'border-radius': '18px',
            'border': '1px solid rgba(255, 255, 255, 0.5)',
            'box-shadow': '0 8px 25px rgba(0, 0, 0, 0.08)',
            'padding': '35px 40px',
            'margin': '20px auto',
            'max-width': '950px',
            'transition': 'all 0.4s ease'
        }).hide().fadeIn(700);

        // 🩵 ترويسة الفورم (العنوان الرئيسي)
        $('.page-head .title-text').css({
            'font-size': '1.6rem',
            'font-weight': '600',
            'color': '#0f172a',
            'letter-spacing': '0.5px'
        });

        // ✨ العناوين الفرعية للأقسام
        $('.form-section .section-head').css({
            'color': '#334155',
            'font-weight': '600',
            'font-size': '1.05rem',
            'border-left': '4px solid #3B82F6',
            'padding-left': '12px',
            'margin-bottom': '10px'
        });

        // 🎛️ تنسيق الحقول
        $('input, select, textarea').css({
            'border-radius': '10px',
            'border': '1px solid #d1d5db',
            'background': 'rgba(255, 255, 255, 0.9)',
            'padding': '10px 12px',
            'transition': 'all 0.3s ease',
            'font-size': '0.95rem'
        }).focus(function() {
            $(this).css({
                'border-color': '#3B82F6',
                'box-shadow': '0 0 8px rgba(59, 130, 246, 0.4)',
                'background': '#fff'
            });
        }).blur(function() {
            $(this).css({
                'border-color': '#d1d5db',
                'box-shadow': 'none',
                'background': 'rgba(255, 255, 255, 0.9)'
            });
        });

        // 💠 الأزرار الرئيسية
        $('.primary-action').css({
            'background': 'linear-gradient(90deg, #3B82F6, #06B6D4)',
            'border': 'none',
            'border-radius': '10px',
            'color': '#fff',
            'font-weight': '600',
            'padding': '10px 26px',
            'box-shadow': '0 4px 15px rgba(59, 130, 246, 0.4)',
            'transition': 'all 0.3s ease'
        }).hover(function() {
            $(this).css({
                'transform': 'translateY(-2px)',
                'box-shadow': '0 6px 18px rgba(59, 130, 246, 0.5)'
            });
        }, function() {
            $(this).css({
                'transform': 'translateY(0)',
                'box-shadow': '0 4px 15px rgba(59, 130, 246, 0.4)'
            });
        });

        // 🌟 تمييز الصفوف في الجداول
        $('.grid-row').hover(function() {
            $(this).css('background', 'rgba(219, 234, 254, 0.4)');
        }, function() {
            $(this).css('background', 'transparent');
        });

        // 🌈 رسالة نجاح صغيرة عند الفتح
        frappe.show_alert({
            message: __('🌤️ تم تحميل الصفحة بتصميم أنيق'),
            indicator: 'blue'
        }, 4);
    }
});

frappe.ui.form.on('Issue', {
    onload: function(frm) {
        // جلب اسم المستخدم الحالي
        if (!frm.doc.user_account) {
            frm.set_value('user_account', frappe.session.user);
        }

        // جلب اسم المرسل من DocType User
        frappe.db.get_value('User', frappe.session.user, 'full_name', (r) => {
            if (r && r.full_name) {
                frm.set_value('sender_name', r.full_name);
            }
        });

        // محاولة جلب اسم الجهاز و IP (يحتاج صلاحيات Client-side)
        frappe.call({
            method: "frappe.client.get_value",
            args: {
                doctype: "User",
                filters: { "name": frappe.session.user },
                fieldname: ["last_ip"]
            },
            callback: function(r) {
                if (r.message && r.message.last_ip) {
                    frm.set_value('device_ip', r.message.last_ip);
                }
            }
        });

        // جلب اسم الجهاز من الـ browser
        try {
            frm.set_value('device_name', window.navigator.userAgent);
        } catch (e) {
            console.log("Error fetching device name:", e);
        }

        // لا يمكن جلب MAC من المتصفح مباشرة (محظور أمنيًا)
        frm.set_df_property('device_mac', 'description', 'يتم تعبئتها يدويًا لأسباب أمان المتصفح');
    }
});

frappe.ui.form.on('اسم_DocType', {
    refresh: function(frm) {
        generate_map(frm);
    },
    الموقع_الخاص_بالمكتب: function(frm) {
        generate_map(frm);
    }
});

function generate_map(frm) {
    if(!frm.doc.الموقع_الخاص_بالمكتب) return;

    try {
        // تحويل GeoJSON إلى إحداثيات
        let geojson = JSON.parse(frm.doc.الموقع_الخاص_بالمكتب);
        let coords = geojson.features[0].geometry.coordinates;
        let lat = coords[1];
        let lng = coords[0];

        let api_key = "YOUR_API_KEY"; // ضع مفتاح Google Maps الخاص بك هنا
        let url = `https://maps.googleapis.com/maps/api/staticmap?center=${lat},${lng}&zoom=15&size=600x300&markers=color:red|${lat},${lng}&key=${api_key}`;

        // جلب الصورة وتحويلها إلى Base64
        fetch(url)
            .then(response => response.blob())
            .then(blob => {
                let reader = new FileReader();
                reader.onloadend = function() {
                    let base64data = reader.result.split(',')[1]; // الحصول على Base64 فقط
                    frm.set_value('map_base64', base64data);
                    frm.save(); // حفظ تلقائي للتحديث
                }
                reader.readAsDataURL(blob);
            })
            .catch(err => {
                frappe.msgprint("خطأ في توليد الخريطة: " + err);
            });
    } catch(e) {
        frappe.msgprint("خطأ في تحليل الموقع: " + e.message);
    }
}

frappe.ui.form.on('Issue', {
    remote_desktob: function(frm) {
        fetch('http://127.0.0.1:5000/run_support')
            .then(res => res.text())
            .then(data => frappe.msgprint(data))
            .catch(err => frappe.msgprint('خطأ في تشغيل التطبيق: ' + err));
    }
});

frappe.ui.form.on('exam_group_date', {
    get_preachers: function(frm) {
        frm.call('get_preachers').then(r => {
            let rows = frm.doc.waed_info_to_exam || [];

            // تفعيل fetch_from يدويًا لكل صف، كأنه تم اختياره من المستخدم
            let promises = rows.map(row => {
                return frappe.model.set_value(row.doctype, row.name, 'waed_info', row.waed_info);
            });

            Promise.all(promises).then(() => {
                frm.refresh_field('waed_info_to_exam');
                frm.refresh_field('count_waes_exam');
                frappe.show_alert({
                    message: __('تم جلب {0} واعظ بنجاح', [rows.length]),
                    indicator: 'green'
                });
            });
        });
    }
});

frappe.ui.form.on('exam_group_date', {
    count_to_exam(frm) {
        const count = frm.doc.count_to_exam;

        if (count <= 0 || count > 30) {
            frappe.msgprint({
                title: __('تنبيه'),
                indicator: 'red',
                message: __('يجب أن يكون عدد المتقدمين بين 1 و 30')
            });

            frm.set_value('count_to_exam', null);
        }
    },

    validate(frm) {
        const count = frm.doc.count_to_exam;

        if (count <= 0 || count > 30) {
            frappe.throw(__('يجب أن يكون عدد المتقدمين بين 1 و 30'));
        }
    }
});
